-- public.admin_api_log DDL
DROP TABLE IF EXISTS "public"."admin_api_log";
CREATE SEQUENCE IF NOT EXISTS "public"."admin_api_log_id_seq";
CREATE TABLE "public"."admin_api_log" (
"id" int8 NOT NULL DEFAULT nextval('admin_api_log_id_seq'::regclass),
"user_id" int8,
"username" varchar(50),
"method" varchar(10) NOT NULL,
"path" varchar(255) NOT NULL,
"query_params" text,
"request_body" text,
"response_code" int4,
"response_body" text,
"duration_ms" int8,
"ip" varchar(50),
"user_agent" varchar(500),
"is_deleted" int4 DEFAULT 0,
"create_time" timestamp(6) DEFAULT CURRENT_TIMESTAMP,
"update_time" timestamp(6) DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT "admin_api_log_pkey" PRIMARY KEY ("id"));

