"request_params" text,
"user_id" int8,
"ip" varchar(50),
"is_deleted" int4 DEFAULT 0,
"create_time" timestamp(6) DEFAULT CURRENT_TIMESTAMP,
"update_time" timestamp(6) DEFAULT CURRENT_TIMESTAMP,
CONSTRAINT "admin_error_log_pkey" PRIMARY KEY ("id"));

